parameters.jsCode:
const email = $input.first().json;

// Extract store code from sender email
// Pattern: SA06.sm@vishalretail.co.in → SA06
const from = email.from?.emailAddress?.address || email.from || '';
const storeMatch = from.match(/^([A-Z]{2}\d{2,3})\.sm@/i);
const storeCode = storeMatch ? storeMatch[1].toUpperCase() : null;

const subject = email.subject || '';
const body    = (email.body?.content || email.bodyPreview || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
const msgId   = email.id || '';
const conversationId = email.conversationId || '';

if (!storeCode) {
  return [{ json: { skip: true, reason: 'Could not extract store code from sender: ' + from, msgId, conversationId } }];
}

return [{ json: { storeCode, from, subject, body: body.slice(0, 1500), msgId, conversationId, skip: false } }];

const d = $input.first().json;
const cid = (d.conversationId || '').replace(/'/g, "''");
if (!cid) {
  return [{ json: { checkQuery: "SELECT 0 as id, '' as complaintno", ...d } }];
}
const checkQuery = `SELECT COALESCE(MAX(id), 0) as id, COALESCE(MAX(complaintno), '') as complaintno FROM vmm_complaints WHERE conversationid IS NOT NULL AND conversationid != '' AND conversationid = '${cid}' AND is_deleted = 'No'`;
return [{ json: { checkQuery, ...d } }];

const emailCtx = $('Extract Store Code').first().json;
const rows = $input.all();
const first = rows[0]?.json;
const existingId = (first?.id && parseInt(first.id) > 0) ? parseInt(first.id) : null;

if (existingId) {
  return [{ json: { isReply: true, existingComplaintId: existingId, complaintno: first.complaintno || '', ...emailCtx } }];
}
return [{ json: { isReply: false, ...emailCtx } }];

const d = $input.first().json;
const esc = v => (v || '').toString().replace(/'/g, "''");
const body = d.body ? d.body.slice(0, 500) : '(no body)';
const subj = d.subject || '';
const insertLog = `INSERT INTO vmm_complaintlogs (complaintid, remarks, status, uid, created, is_deleted) VALUES (${d.existingComplaintId}, '${esc(body)} | Source: Email Follow-up | Subject: ${esc(subj)}', 'In Progress', 1, NOW(), 'No')`;
const htmlBody = `<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.7;max-width:600px"><p>Dear Store Team,</p><p>We have received your follow-up on complaint <strong>${d.complaintno}</strong>. Your message has been noted and our team is actively working on the resolution.</p><p>If you require immediate assistance, please contact our helpdesk.</p><hr style="margin:16px 0;border:none;border-top:1px solid #e2e8f0"/><p style="font-size:11px;color:#64748b">VMM CRM — Open Mind Services Limited</p></div>`;
return [{ json: { ...d, insertLog, htmlBody } }];

