parameters.jsCode:
const emailCtx  = $('Extract Store Code').first().json;
const storeRes  = $('Lookup Store').first().json;
const aiRes     = $('OpenAI Extract Details').first().json;

const store = storeRes.found ? storeRes.store : null;
if (!store) return [{ json: { skip: true, reason: 'Store not found in sheet for code: ' + emailCtx.storeCode } }];

let extracted = {};
try {
  const raw = aiRes?.choices?.[0]?.message?.content || '{}';
  extracted = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch { extracted = {}; }

const productName     = (extracted.productName     || 'General Complaint').replace(/'/g, "''");
const natureOfProblem = (extracted.natureOfProblem || 'Not Specified').replace(/'/g, "''");
const description     = (extracted.description     || emailCtx.body.slice(0, 500)).replace(/'/g, "''");

const esc = v => (v || '').toString().replace(/'/g, "''");

const tat = 7;
const edc = new Date();
edc.setDate(edc.getDate() + tat);
const edcStr = edc.toISOString().split('T')[0];

const insertStore = `INSERT INTO vmm_complaintstores (storecode, storename, storecity, storeregion, statename, zone, fmname, managername, asmname, uid, created, is_deleted) VALUES ('${esc(store.code)}', '${esc(store.name)}', '${esc(store.city)}', '${esc(store.region)}', '${esc(store.state)}', '${esc(store.zone)}', '${esc(store.fmName)}', '${esc(store.managerName)}', '${esc(store.asmName)}', 1, NOW(), 'No')`;

return [{ json: {
  insertStore, productName, natureOfProblem, description, tat, edcStr,
  storeCode: store.code, storeName: store.name, storeEmail: store.email || '',
  emailSubject: emailCtx.subject, msgId: emailCtx.msgId, fromEmail: emailCtx.from,
  conversationId: emailCtx.conversationId || '',
  skip: false
} }];

const prev      = $('Build Store INSERT').first().json;
const storeRow  = $input.first().json;
const storeRefId = storeRow.insertId || (Array.isArray(storeRow) ? storeRow[0]?.insertId : null) || 0;

const esc = v => (v || '').toString().replace(/'/g, "''");

const insertComplaint = `INSERT INTO vmm_complaints (storerefid, productname, producttype, vendorname, productlocation, natureofproblem, typeofcomplaint, tat, conversationid, uid, created, is_deleted) VALUES (${storeRefId}, '${esc(prev.productName)}', '', '', 'See email', '${esc(prev.natureOfProblem)}', 'Repair', ${prev.tat}, '${esc(prev.conversationId)}', 1, NOW(), 'No')`;

return [{ json: { insertComplaint, storeRefId, prev } }];

const prev        = $('Build Complaint INSERT').first().json;
const cRow        = $input.first().json;
const complaintId = cRow.insertId || (Array.isArray(cRow) ? cRow[0]?.insertId : null) || 0;

const now = new Date();
const yy  = String(now.getFullYear()).slice(-2);
const mm  = String(now.getMonth() + 1).padStart(2, '0');
const dd  = String(now.getDate()).padStart(2, '0');
const seq = String(complaintId).padStart(6, '0').slice(-6);
const complaintno = yy + mm + dd + seq;

const p = prev.prev;
const esc = v => (v || '').toString().replace(/'/g, "''");
const desc = esc(p.description);
const subj = esc(p.emailSubject);

const insertEsc = `INSERT INTO vmm_vendorescalations (complaintid, ticketno, escalationlevel, closuredate, uid, created, is_deleted) VALUES (${complaintId}, '', 1, '${p.edcStr}', 1, NOW(), 'No')`;
const insertLog = `INSERT INTO vmm_complaintlogs (complaintid, remarks, status, uid, created, is_deleted) VALUES (${complaintId}, '${desc} | Source: Email | Subject: ${subj}', 'Open', 1, NOW(), 'No')`;
const updateNo  = `UPDATE vmm_complaints SET complaintno = '${complaintno}' WHERE id = ${complaintId}`;

return [{ json: { complaintId, complaintno, insertEsc, insertLog, updateNo, p } }];

const cfg = $('Email Config').first().json;
const d   = $('Generate Complaint No').first().json;
const p   = d.p;

const toAddress = cfg.TEST_MODE ? cfg.TEST_TO : (p.storeEmail || 'vmm@openmindserviceslimited.in');
const ccAddress = cfg.ALWAYS_CC || '';

const htmlBody =
  '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.7;max-width:600px">'
  + '<p>Dear Store Team,</p>'
  + '<p>Thank you for reaching out. Your complaint has been registered successfully. Please find the details below:</p>'
  + '<table style="border-collapse:collapse;width:100%;margin:12px 0">'
  + '<tr><td style="padding:8px 12px;background:#f8fafc;font-weight:700;width:40%">Complaint No</td><td style="padding:8px 12px;border-bottom:1px solid #e2e8f0;font-weight:800;color:#1e1b4b">' + d.complaintno + '</td></tr>'
  + '<tr><td style="padding:8px 12px;background:#f8fafc;font-weight:700">Store</td><td style="padding:8px 12px;border-bottom:1px solid #e2e8f0">' + p.storeName + ' (' + p.storeCode + ')</td></tr>'
  + '<tr><td style="padding:8px 12px;background:#f8fafc;font-weight:700">Product</td><td style="padding:8px 12px;border-bottom:1px solid #e2e8f0">' + p.productName + '</td></tr>'
  + '<tr><td style="padding:8px 12px;background:#f8fafc;font-weight:700">Expected Closure</td><td style="padding:8px 12px;font-weight:700;color:#dc2626">' + p.edcStr + '</td></tr>'
  + '</table>'
  + '<p>Our team will follow up within the expected closure date. Please reply to this email or call us if you need immediate assistance.</p>'
  + '<hr style="margin:16px 0;border:none;border-top:1px solid #e2e8f0"/>'
  + '<p style="font-size:11px;color:#64748b">Automated response from VMM CRM — Open Mind Services Limited.</p>'
  + (cfg.TEST_MODE
      ? '<hr style="margin:12px 0;border:none;border-top:1px solid #fcd34d"/><p style="font-size:11px;color:#92400e"><strong>TEST MODE</strong> — Original recipient: ' + (p.storeEmail || '(none on record)') + '</p>'
      : '')
  + '</div>';

return [{ json: { subject: 'VMM Complaint Confirmation' + (cfg.TEST_MODE ? ' [TEST MODE]' : '') + ' - ' + d.complaintno, htmlBody, toAddress, ccAddress } }];
